import React, { useEffect, useState } from 'react';
import ProductForm from '../components/ProductForm';
import ProductList from '../components/ProductList';
import StockMovementForm from '../components/StockMovementForm';

import axios from 'axios';

const Products = () => {
    const [products, setProducts] = useState([]);
    const [selectedProduct, setSelectedProduct] = useState(null);

    // Buscar produtos da API
    const fetchProducts = async () => {
        try {
            const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
            setProducts(response.data);
        } catch (error) {
            console.error("Erro ao buscar produtos:", error);
        }
    };

    // Atualizar produto no banco e na lista
    const updateProductQuantity = async (productId, tipoMovimentacao, quantidade) => {
        try {
            const produto = products.find(p => p.id === productId);
            if (!produto) return;

            const novaQuantidade = tipoMovimentacao === 'entrada'
                ? produto.quantidade + quantidade
                : produto.quantidade - quantidade;

            await axios.put(`http://127.0.0.1:8000/api/produtos/${productId}/`, {
                quantidade: novaQuantidade
            });

            fetchProducts();
        } catch (error) {
            console.error("Erro ao atualizar quantidade do produto:", error);
        }
    };

    // Deletar um produto
    const handleDelete = async (productId) => {
        try {
            await axios.delete(`http://127.0.0.1:8000/api/produtos/${productId}/`);
            fetchProducts(); // Atualiza a lista após deletar
        } catch (error) {
            console.error("Erro ao deletar produto:", error);
        }
    };

    useEffect(() => {
        fetchProducts();
    }, []);

    return (
        <div>
            <h2>Gerenciar Produtos</h2>
            <ProductForm refreshProducts={fetchProducts} selectedProduct={selectedProduct} setSelectedProduct={setSelectedProduct} />
            <ProductList products={products} onEdit={setSelectedProduct} onDelete={handleDelete} />
            <h2>Movimentação de Estoque</h2>
            <StockMovementForm refreshProducts={fetchProducts} updateProductQuantity={updateProductQuantity} />
        </div>
    );
};

export default Products;
